-- ============================================================
-- Milestones of Human Progress — starter dataset (trilingual)
-- Run AFTER db/schema.sql, in the Supabase SQL editor.
--
-- Notes:
--  * Text values use Postgres dollar-quoting ($$...$$) so apostrophes in
--    Italian/English need no escaping.
--  * Fixed UUIDs are used so figure_id / location_id / led_to stay linked.
--  * The leading DELETEs make this script safe to re-run (idempotent).
--  * 25 milestones span Antiquity -> Digital age and all nine fields,
--    with the Chinese 四大发明 (paper, printing, compass, gunpowder) included.
-- ============================================================

delete from stp_milestones;
delete from stp_figures;
delete from stp_locations;

