insert into stp_milestones (id, field, title_zh, title_it, title_en, desc_zh, desc_it, desc_en, year, era, figure_id, location_id, led_to) values
('30000000-0000-4000-8000-000000000001', $$physics$$, $$阿基米德原理$$, $$Principio di Archimede$$, $$Archimedes' Principle$$,
  $$阿基米德发现：浸入流体中的物体受到的浮力等于它排开流体的重量——这是流体静力学与船舶设计的基础。$$,
  $$Archimede scoprì che un corpo immerso in un fluido riceve una spinta verso l'alto pari al peso del fluido spostato — fondamento dell'idrostatica e della progettazione navale.$$,
  $$Archimedes discovered that a body immersed in a fluid is buoyed up by a force equal to the weight of the fluid it displaces — the foundation of hydrostatics and ship design.$$,
  -250, $$Ancient$$, '20000000-0000-4000-8000-000000000001', '10000000-0000-4000-8000-000000000001', '{}'::uuid[]),
('30000000-0000-4000-8000-000000000002', $$astronomy$$, $$安提基特拉机械$$, $$La macchina di Anticitera$$, $$The Antikythera Mechanism$$,
  $$从希腊沉船中打捞出的青铜齿轮装置，可预测日月食与行星位置——已知最早的模拟计算机。$$,
  $$Recuperato da un relitto greco, questo dispositivo di bronzo a ingranaggi prevedeva eclissi e posizioni planetarie: il più antico calcolatore analogico conosciuto.$$,
  $$Recovered from a Greek shipwreck, this geared bronze device could predict eclipses and planetary positions — the earliest known analog computer.$$,
  -100, $$Ancient$$, null, '10000000-0000-4000-8000-000000000002', '{}'::uuid[]),
('30000000-0000-4000-8000-000000000003', $$communication$$, $$造纸术$$, $$L'invenzione della carta$$, $$Papermaking$$,
  $$蔡伦以树皮、麻头和破布改进造纸，使其廉价实用，让知识在中国乃至全世界传播。$$,
  $$Cai Lun perfezionò la fabbricazione della carta da corteccia, canapa e stracci, creando un supporto economico che diffuse il sapere in Cina e poi nel mondo.$$,
  $$Cai Lun refined papermaking from bark, hemp and rags into a cheap, practical medium that spread knowledge across China and, eventually, the world.$$,
  105, $$Ancient$$, '20000000-0000-4000-8000-000000000002', '10000000-0000-4000-8000-000000000003', array['30000000-0000-4000-8000-000000000005']::uuid[]),
('30000000-0000-4000-8000-000000000004', $$energy$$, $$火药$$, $$La polvere da sparo$$, $$Gunpowder$$,
  $$中国炼丹师在寻求长生不老药时意外发明了火药，改变了战争、采矿，乃至后来的烟花。$$,
  $$Gli alchimisti cinesi, in cerca di un elisir d'immortalità, crearono invece la polvere da sparo, trasformando guerra, miniere e poi i fuochi d'artificio.$$,
  $$Chinese alchemists seeking an elixir of immortality instead created gunpowder, transforming warfare, mining and, later, fireworks.$$,
  850, $$Ancient$$, null, '10000000-0000-4000-8000-000000000004', '{}'::uuid[]),
('30000000-0000-4000-8000-000000000005', $$communication$$, $$活字印刷术$$, $$La stampa a caratteri mobili$$, $$Movable-Type Printing$$,
  $$毕昇发明可重复使用的胶泥活字，使书页得以排版和重印——比欧洲古腾堡的印刷机早了数百年。$$,
  $$Bi Sheng creò caratteri riutilizzabili in argilla, permettendo di comporre e ristampare le pagine — secoli prima della stampa di Gutenberg in Europa.$$,
  $$Bi Sheng created reusable clay type, allowing pages to be assembled and reprinted — centuries before Gutenberg's press in Europe.$$,
  1040, $$Ancient$$, '20000000-0000-4000-8000-000000000003', '10000000-0000-4000-8000-000000000005', '{}'::uuid[]),
('30000000-0000-4000-8000-000000000006', $$transport$$, $$指南针$$, $$La bussola magnetica$$, $$The Magnetic Compass$$,
  $$沈括记述了磁针指向子午线的原理，为航海者提供可靠指引，开启了远洋航行的时代。$$,
  $$Shen Kuo descrisse come un ago magnetizzato si allinei al meridiano, offrendo ai naviganti una guida affidabile e aprendo l'era della navigazione oceanica.$$,
  $$Shen Kuo described how a magnetized needle points along the meridian, giving sailors a reliable guide and opening the age of ocean navigation.$$,
  1088, $$Ancient$$, '20000000-0000-4000-8000-000000000004', '10000000-0000-4000-8000-000000000006', '{}'::uuid[]),
('30000000-0000-4000-8000-000000000007', $$astronomy$$, $$日心说$$, $$L'eliocentrismo$$, $$Heliocentrism$$,
  $$哥白尼提出地球与行星绕太阳运行，把人类从宇宙中心移开，开启了科学革命。$$,
  $$Copernico sostenne che la Terra e i pianeti orbitano attorno al Sole, spostando l'umanità dal centro dell'universo e avviando la Rivoluzione Scientifica.$$,
  $$Copernicus argued that the Earth and planets orbit the Sun, displacing humanity from the center of the universe and launching the Scientific Revolution.$$,
  1543, $$Renaissance$$, '20000000-0000-4000-8000-000000000005', '10000000-0000-4000-8000-000000000007', array['30000000-0000-4000-8000-000000000008']::uuid[]),
('30000000-0000-4000-8000-000000000008', $$astronomy$$, $$伽利略的望远镜$$, $$Il telescopio di Galileo$$, $$Galileo's Telescope$$,
  $$伽利略将改良的望远镜对准天空，看到木星的卫星和金星的相位——这是并非万物都绕地球运行的观测证据。$$,
  $$Puntando al cielo un telescopio perfezionato, Galileo vide le lune di Giove e le fasi di Venere: prova osservativa che non tutto orbita attorno alla Terra.$$,
  $$Turning an improved telescope to the sky, Galileo saw Jupiter's moons and the phases of Venus — observational proof that not everything orbits the Earth.$$,
  1609, $$Renaissance$$, '20000000-0000-4000-8000-000000000006', '10000000-0000-4000-8000-000000000008', array['30000000-0000-4000-8000-000000000009']::uuid[]),
('30000000-0000-4000-8000-000000000009', $$physics$$, $$牛顿运动定律与万有引力$$, $$Le leggi di Newton sul moto e la gravità$$, $$Newton's Laws of Motion & Gravity$$,
  $$牛顿用三大运动定律与万有引力把天与地统一起来，为科学提供了第一个完整的物理理论。$$,
  $$Newton unificò cielo e Terra con tre leggi del moto e la gravitazione universale, dando alla scienza la sua prima teoria fisica completa.$$,
  $$Newton unified the heavens and the Earth under three laws of motion and universal gravitation, giving science its first complete physical theory.$$,
  1687, $$Renaissance$$, '20000000-0000-4000-8000-000000000007', '10000000-0000-4000-8000-000000000009', array['30000000-0000-4000-8000-000000000016']::uuid[]),
('30000000-0000-4000-8000-000000000010', $$energy$$, $$瓦特蒸汽机$$, $$La macchina a vapore di Watt$$, $$Watt's Steam Engine$$,
  $$瓦特的分离式冷凝器大幅提升了蒸汽机效率，为工厂、铁路和工业革命提供了动力。$$,
  $$Il condensatore separato di Watt rese la macchina a vapore molto più efficiente, alimentando fabbriche, ferrovie e la Rivoluzione Industriale.$$,
  $$Watt's separate condenser made the steam engine vastly more efficient, powering factories, railways and the Industrial Revolution.$$,
  1776, $$Industrial$$, '20000000-0000-4000-8000-000000000008', '10000000-0000-4000-8000-000000000010', '{}'::uuid[]),
('30000000-0000-4000-8000-000000000011', $$energy$$, $$伏打电堆（电池）$$, $$La pila voltaica$$, $$The Voltaic Pile (Battery)$$,
  $$伏特将铜片与锌片叠放，产生稳定电流——这是第一个电池，也是电学的开端。$$,
  $$Volta impilò dischi di rame e zinco per produrre una corrente elettrica costante: la prima batteria e l'inizio della scienza elettrica.$$,
  $$Volta stacked discs of copper and zinc to produce a steady electric current — the first battery, and the start of electrical science.$$,
  1800, $$Industrial$$, '20000000-0000-4000-8000-000000000009', '10000000-0000-4000-8000-000000000011', array['30000000-0000-4000-8000-000000000012']::uuid[]),
('30000000-0000-4000-8000-000000000012', $$physics$$, $$电磁感应$$, $$L'induzione elettromagnetica$$, $$Electromagnetic Induction$$,
  $$法拉第证明变化的磁场能产生电流，这是一切发电机、变压器与电动机的原理。$$,
  $$Faraday dimostrò che un campo magnetico variabile genera elettricità, principio alla base di ogni generatore, trasformatore e motore elettrico.$$,
  $$Faraday showed that a changing magnetic field generates electricity, the principle behind every generator, transformer and electric motor.$$,
  1831, $$Industrial$$, '20000000-0000-4000-8000-000000000010', '10000000-0000-4000-8000-000000000012', array['30000000-0000-4000-8000-000000000014']::uuid[]),
('30000000-0000-4000-8000-000000000013', $$biology_chemistry$$, $$进化论$$, $$La teoria dell'evoluzione$$, $$The Theory of Evolution$$,
  $$达尔文在《物种起源》中以自然选择的进化论解释了生命的多样性，重塑了整个生物学。$$,
  $$In «L'origine delle specie», Darwin spiegò la diversità della vita attraverso l'evoluzione per selezione naturale, trasformando tutta la biologia.$$,
  $$In On the Origin of Species, Darwin explained the diversity of life through evolution by natural selection, reshaping all of biology.$$,
  1859, $$Industrial$$, '20000000-0000-4000-8000-000000000011', '10000000-0000-4000-8000-000000000013', '{}'::uuid[]),
('30000000-0000-4000-8000-000000000014', $$communication$$, $$无线电$$, $$La radio senza fili$$, $$Wireless Radio$$,
  $$马可尼实现了无线电信号的空中传输，最终跨越大西洋，让世界实现实时连接。$$,
  $$Marconi trasmise segnali nell'aria senza fili, attraversando infine l'Atlantico e collegando il mondo in tempo reale.$$,
  $$Marconi transmitted signals through the air without wires, eventually spanning the Atlantic and connecting the world in real time.$$,
  1895, $$Modern$$, '20000000-0000-4000-8000-000000000012', '10000000-0000-4000-8000-000000000014', '{}'::uuid[]),
('30000000-0000-4000-8000-000000000015', $$physics$$, $$放射性$$, $$La radioattività$$, $$Radioactivity$$,
  $$玛丽·居里对钋、镭等放射性元素的研究，开启了核物理与现代医学的大门。$$,
  $$Lo studio di Marie Curie su elementi radioattivi come polonio e radio aprì la strada alla fisica nucleare e alla medicina moderna.$$,
  $$Marie Curie's study of radioactive elements like polonium and radium opened the door to nuclear physics and modern medicine.$$,
  1898, $$Modern$$, '20000000-0000-4000-8000-000000000013', '10000000-0000-4000-8000-000000000015', array['30000000-0000-4000-8000-000000000018']::uuid[]),
('30000000-0000-4000-8000-000000000016', $$physics$$, $$相对论$$, $$La teoria della relatività$$, $$The Theory of Relativity$$,
  $$爱因斯坦揭示时间与空间交织、质量与能量等价（E=mc²），重新定义了物理学与宇宙学。$$,
  $$Einstein dimostrò che spazio e tempo sono intrecciati e che massa ed energia sono equivalenti (E=mc²), ridefinendo fisica e cosmologia.$$,
  $$Einstein showed that space and time are interwoven and that mass and energy are equivalent (E=mc²), redefining physics and cosmology.$$,
  1905, $$Modern$$, '20000000-0000-4000-8000-000000000014', '10000000-0000-4000-8000-000000000016', array['30000000-0000-4000-8000-000000000018']::uuid[]),
('30000000-0000-4000-8000-000000000017', $$medicine$$, $$青霉素$$, $$La penicillina$$, $$Penicillin$$,
  $$弗莱明注意到实验室里一种霉菌能杀死细菌，由此诞生了第一种抗生素青霉素，迄今已挽救数亿生命。$$,
  $$Fleming notò una muffa che uccideva i batteri nel suo laboratorio, dando origine alla penicillina — il primo antibiotico, che da allora ha salvato centinaia di milioni di vite.$$,
  $$Fleming noticed a mould killing bacteria in his lab, leading to penicillin — the first antibiotic, which has since saved hundreds of millions of lives.$$,
  1928, $$Modern$$, '20000000-0000-4000-8000-000000000015', '10000000-0000-4000-8000-000000000017', '{}'::uuid[]),
('30000000-0000-4000-8000-000000000018', $$energy$$, $$首座核反应堆$$, $$Il primo reattore nucleare$$, $$The First Nuclear Reactor$$,
  $$费米团队在芝加哥一座球场看台下实现了首次受控自持核链式反应，释放了核能。$$,
  $$Il team di Fermi realizzò la prima reazione nucleare a catena controllata e autosostenuta sotto uno stadio di Chicago, liberando l'energia nucleare.$$,
  $$Fermi's team achieved the first controlled, self-sustaining nuclear chain reaction under a Chicago stadium, unleashing nuclear energy.$$,
  1942, $$Modern$$, '20000000-0000-4000-8000-000000000016', '10000000-0000-4000-8000-000000000018', '{}'::uuid[]),
('30000000-0000-4000-8000-000000000019', $$biology_chemistry$$, $$DNA 结构$$, $$La struttura del DNA$$, $$The Structure of DNA$$,
  $$在富兰克林 X 射线图像的基础上，沃森与克里克揭示了 DNA 双螺旋，解释了生命如何存储与复制信息。$$,
  $$Sulla base delle immagini a raggi X di Franklin, Watson e Crick svelarono la doppia elica del DNA, spiegando come la vita conserva e copia le proprie informazioni.$$,
  $$Building on Franklin's X-ray images, Watson and Crick revealed DNA's double helix, explaining how life stores and copies its information.$$,
  1953, $$Modern$$, '20000000-0000-4000-8000-000000000017', '10000000-0000-4000-8000-000000000019', array['30000000-0000-4000-8000-000000000024']::uuid[]),
('30000000-0000-4000-8000-000000000020', $$computing$$, $$计算理论$$, $$La teoria della computazione$$, $$The Theory of Computation$$,
  $$图灵提出的抽象「机器」定义了「计算」的含义，为此后所有计算机奠定了理论基础。$$,
  $$La 'macchina' astratta di Turing definì cosa significhi calcolare, ponendo le basi teoriche di ogni computer successivo.$$,
  $$Turing's abstract 'machine' defined what it means to compute, laying the theoretical foundation for every computer that followed.$$,
  1936, $$Modern$$, '20000000-0000-4000-8000-000000000018', '10000000-0000-4000-8000-000000000020', array['30000000-0000-4000-8000-000000000021']::uuid[]),
('30000000-0000-4000-8000-000000000021', $$computing$$, $$晶体管$$, $$Il transistor$$, $$The Transistor$$,
  $$贝尔实验室发明的微型半导体开关取代了笨重的真空管，使一切现代电子技术与数字时代成为可能。$$,
  $$Il minuscolo interruttore a semiconduttore inventato ai Bell Labs sostituì i voluminosi tubi a vuoto e rese possibile tutta l'elettronica moderna e l'era digitale.$$,
  $$The tiny semiconductor switch invented at Bell Labs replaced bulky vacuum tubes and made all modern electronics — and the digital age — possible.$$,
  1947, $$Modern$$, '20000000-0000-4000-8000-000000000019', '10000000-0000-4000-8000-000000000021', array['30000000-0000-4000-8000-000000000023','30000000-0000-4000-8000-000000000025']::uuid[]),
('30000000-0000-4000-8000-000000000022', $$space$$, $$阿波罗 11 号登月$$, $$Lo sbarco sulla Luna dell'Apollo 11$$, $$Apollo 11 Moon Landing$$,
  $$1969 年 7 月 20 日，人类首次踏上月球，这是太空竞赛的巅峰，也是全人类的里程碑。$$,
  $$Il 20 luglio 1969 l'uomo camminò sulla Luna per la prima volta, coronamento della corsa allo spazio e traguardo per l'intera umanità.$$,
  $$On 20 July 1969 humans walked on the Moon for the first time, the crowning achievement of the Space Race and a milestone for all humanity.$$,
  1969, $$Modern$$, '20000000-0000-4000-8000-000000000020', '10000000-0000-4000-8000-000000000022', '{}'::uuid[]),
('30000000-0000-4000-8000-000000000023', $$communication$$, $$万维网$$, $$Il World Wide Web$$, $$The World Wide Web$$,
  $$在欧洲核子研究中心，伯纳斯-李将超文本与互联网结合创造出万维网，把计算机网络变成共享知识的通用空间。$$,
  $$Al CERN, Berners-Lee unì l'ipertesto a Internet creando il Web, trasformando una rete di computer in uno spazio universale per condividere il sapere.$$,
  $$At CERN, Berners-Lee combined hypertext with the internet to create the Web, turning a network of computers into a universal space for sharing knowledge.$$,
  1989, $$Digital$$, '20000000-0000-4000-8000-000000000021', '10000000-0000-4000-8000-000000000023', '{}'::uuid[]),
('30000000-0000-4000-8000-000000000024', $$biology_chemistry$$, $$CRISPR 基因编辑$$, $$L'editing genetico CRISPR$$, $$CRISPR Gene Editing$$,
  $$CRISPR-Cas9 让科学家以前所未有的精度和便捷编辑 DNA，正在变革生物学、医学与农业。$$,
  $$CRISPR-Cas9 permette di modificare il DNA con precisione e facilità senza precedenti, trasformando biologia, medicina e agricoltura.$$,
  $$CRISPR-Cas9 lets scientists edit DNA with unprecedented precision and ease, transforming biology, medicine and agriculture.$$,
  2012, $$Digital$$, '20000000-0000-4000-8000-000000000022', '10000000-0000-4000-8000-000000000024', '{}'::uuid[]),
('30000000-0000-4000-8000-000000000025', $$computing$$, $$深度学习革命$$, $$La rivoluzione del deep learning$$, $$The Deep-Learning Revolution$$,
  $$2012 年 ImageNet 竞赛中神经网络的突破性胜利表明机器能够学会「看」，点燃了当今的人工智能时代。$$,
  $$La vittoria rivoluzionaria di una rete neurale al concorso ImageNet del 2012 mostrò che le macchine possono imparare a vedere, accendendo l'odierna era dell'intelligenza artificiale.$$,
  $$A neural network's breakthrough win at the 2012 ImageNet contest showed that machines could learn to see, igniting today's era of artificial intelligence.$$,
  2012, $$Digital$$, '20000000-0000-4000-8000-000000000023', '10000000-0000-4000-8000-000000000025', '{}'::uuid[]);

-- ---------------------------------------------------------------
-- (v2) ECONOMY & INDUSTRY MILESTONES
-- Listed with explicit category; the science_tech block above relies on the
-- default 'science_tech' value defined in the v2 schema.
-- ---------------------------------------------------------------
insert into stp_milestones (id, category, field, title_zh, title_it, title_en, desc_zh, desc_it, desc_en, year, era, figure_id, location_id, led_to) values
('30000000-0000-4000-8000-000000000026', $$economy_industry$$, $$agriculture$$, $$小麦的驯化$$, $$La domesticazione del grano$$, $$Domestication of Wheat$$,
  $$在新月沃地，人类从野生小麦中选育出可栽培品种，开启了定居农业与城市的诞生。$$,
  $$Nella Mezzaluna Fertile, gli esseri umani selezionarono dal grano selvatico le prime varietà coltivabili, dando inizio all'agricoltura sedentaria e alla nascita delle città.$$,
  $$In the Fertile Crescent, humans selected cultivable varieties from wild wheat, beginning settled agriculture and the rise of cities.$$,
  -9000, $$Ancient$$, null, '10000000-0000-4000-8000-000000000026', array['30000000-0000-4000-8000-000000000037']::uuid[]),
('30000000-0000-4000-8000-000000000027', $$economy_industry$$, $$agriculture$$, $$犁的发明$$, $$L'invenzione dell'aratro$$, $$The Plough$$,
  $$美索不达米亚的农人用犁翻耕土地，使大规模耕作成为可能，奠定了文明赖以为生的粮食基础。$$,
  $$Gli agricoltori della Mesopotamia usarono l'aratro per rivoltare la terra, rendendo possibile la coltivazione su larga scala su cui si fondano le civiltà.$$,
  $$Mesopotamian farmers used the plough to turn the soil, making large-scale cultivation — and the food surplus on which civilization depends — possible.$$,
  -3000, $$Ancient$$, null, '10000000-0000-4000-8000-000000000027', '{}'::uuid[]),
('30000000-0000-4000-8000-000000000028', $$economy_industry$$, $$trade$$, $$丝绸之路开通$$, $$L'apertura della Via della Seta$$, $$The Silk Road Opens$$,
  $$张骞出使西域后，连接中国与地中海世界的商路逐步形成，丝绸、香料、思想与技术沿途流动了一千五百年。$$,
  $$Dopo le missioni di Zhang Qian in Asia centrale, prese forma la rete di vie che collegò la Cina al mondo mediterraneo: seta, spezie, idee e tecnologie viaggiarono lungo la Via della Seta per millecinquecento anni.$$,
  $$After Zhang Qian's missions to Central Asia, a network of trade routes took shape linking China to the Mediterranean world — silk, spices, ideas and technologies travelled the Silk Road for fifteen centuries.$$,
  -130, $$Ancient$$, '20000000-0000-4000-8000-000000000024', '10000000-0000-4000-8000-000000000028', '{}'::uuid[]),
('30000000-0000-4000-8000-000000000029', $$economy_industry$$, $$agriculture$$, $$三圃制轮作$$, $$La rotazione dei tre campi$$, $$Three-Field Crop Rotation$$,
  $$中世纪欧洲的三圃轮作制度让土地常年保持地力，大幅提升了粮食产量，养活了不断增长的城镇人口。$$,
  $$La rotazione triennale dei campi nell'Europa medievale mantenne la fertilità del suolo e aumentò notevolmente la produttività agricola, sostenendo la crescita delle città.$$,
  $$Medieval Europe's three-field rotation kept soil fertile year-round and sharply raised yields, feeding a growing urban population.$$,
  800, $$Ancient$$, null, '10000000-0000-4000-8000-000000000029', '{}'::uuid[]),
('30000000-0000-4000-8000-000000000030', $$economy_industry$$, $$finance$$, $$纸币（交子）$$, $$La moneta cartacea (Jiaozi)$$, $$Paper Money (Jiaozi)$$,
  $$北宋时期成都商人首创汇票式的纸币「交子」，后由朝廷接管发行，开启了世界纸币史。$$,
  $$I commercianti di Chengdu nella dinastia Song crearono Jiaozi, le prime banconote, poi emesse dallo Stato: l'inizio della storia mondiale della moneta cartacea.$$,
  $$In Song-dynasty Chengdu, merchants issued Jiaozi — the world's first paper money — soon taken over by the state, beginning the global history of banknotes.$$,
  1024, $$Ancient$$, null, '10000000-0000-4000-8000-000000000030', '{}'::uuid[]),
('30000000-0000-4000-8000-000000000031', $$economy_industry$$, $$finance$$, $$美第奇银行$$, $$La Banca dei Medici$$, $$The Medici Bank$$,
  $$乔瓦尼·迪·比奇·德·美第奇在佛罗伦萨创立美第奇银行，以分行网络和复式记账推动了文艺复兴的金融与艺术。$$,
  $$Giovanni di Bicci de' Medici fondò a Firenze la Banca dei Medici: una rete di filiali e la partita doppia che alimentarono la finanza e l'arte del Rinascimento.$$,
  $$Giovanni di Bicci de' Medici founded the Medici Bank in Florence; its branch network and double-entry bookkeeping powered the finance — and the art — of the Renaissance.$$,
  1397, $$Renaissance$$, '20000000-0000-4000-8000-000000000025', '10000000-0000-4000-8000-000000000031', array['30000000-0000-4000-8000-000000000032']::uuid[]),
('30000000-0000-4000-8000-000000000032', $$economy_industry$$, $$finance$$, $$荷兰东印度公司（首家股份公司）$$, $$La Compagnia delle Indie Orientali (la prima società per azioni)$$, $$The Dutch East India Company (First Joint-Stock Company)$$,
  $$VOC 把风险和回报分散到公开发行的股份上，发明了股份公司与股票市场，奠定了现代资本主义的基石。$$,
  $$La VOC distribuì rischi e profitti tra azioni pubblicamente negoziabili, inventando la società per azioni e la borsa: una pietra angolare del capitalismo moderno.$$,
  $$By spreading risk and reward across publicly tradable shares, the VOC invented the joint-stock company and the stock market — a cornerstone of modern capitalism.$$,
  1602, $$Renaissance$$, null, '10000000-0000-4000-8000-000000000032', '{}'::uuid[]),
('30000000-0000-4000-8000-000000000033', $$economy_industry$$, $$industry$$, $$珍妮纺纱机$$, $$La Spinning Jenny$$, $$The Spinning Jenny$$,
  $$哈格里夫斯发明的多锭纺纱机让一名工人可以同时纺多根纱，开启了纺织业的机械化，也是工业革命的起点之一。$$,
  $$La macchina filatrice multi-fuso di Hargreaves permise a un singolo operaio di filare più fili contemporaneamente, avviando la meccanizzazione tessile — un punto di partenza della Rivoluzione Industriale.$$,
  $$Hargreaves's multi-spindle frame let one worker spin many threads at once, mechanizing textiles and marking one of the starting points of the Industrial Revolution.$$,
  1764, $$Industrial$$, '20000000-0000-4000-8000-000000000026', '10000000-0000-4000-8000-000000000033', array['30000000-0000-4000-8000-000000000036']::uuid[]),
('30000000-0000-4000-8000-000000000034', $$economy_industry$$, $$industry$$, $$贝塞麦炼钢法$$, $$Il convertitore Bessemer$$, $$The Bessemer Steel Process$$,
  $$贝塞麦的转炉法把炼钢成本和时间砍掉几十倍，让钢材成为铁路、摩天楼和现代工业的基础材料。$$,
  $$Il convertitore di Bessemer ridusse di decine di volte costo e tempo di produzione dell'acciaio, rendendolo il materiale di base per ferrovie, grattacieli e industria moderna.$$,
  $$Bessemer's converter cut the cost and time of making steel many times over, making it the base material of railways, skyscrapers and modern industry.$$,
  1856, $$Industrial$$, '20000000-0000-4000-8000-000000000027', '10000000-0000-4000-8000-000000000034', array['30000000-0000-4000-8000-000000000036']::uuid[]),
('30000000-0000-4000-8000-000000000035', $$economy_industry$$, $$labor$$, $$八小时工作制运动（干草市场事件）$$, $$Il movimento per le otto ore (Haymarket)$$, $$The Eight-Hour Workday Movement (Haymarket)$$,
  $$1886 年芝加哥的干草市场事件让「八小时工作制」成为全球劳工运动的旗帜，最终确立了现代劳动时间标准。$$,
  $$L'evento di Haymarket a Chicago nel 1886 trasformò le «otto ore» in bandiera del movimento operaio mondiale, fissando lo standard moderno dell'orario di lavoro.$$,
  $$The 1886 Haymarket affair in Chicago made the eight-hour workday a global rallying cry for the labor movement, fixing the modern standard for working hours.$$,
  1886, $$Industrial$$, null, '10000000-0000-4000-8000-000000000035', '{}'::uuid[]),
('30000000-0000-4000-8000-000000000036', $$economy_industry$$, $$industry$$, $$流水装配线$$, $$La catena di montaggio$$, $$The Moving Assembly Line$$,
  $$福特在底特律高地公园工厂引入流水装配线，把一辆 T 型车的装配时间从十二小时缩短到九十分钟，让汽车走入普通家庭。$$,
  $$Ford introdusse a Highland Park la catena di montaggio in movimento, riducendo l'assemblaggio della Model T da dodici ore a novanta minuti e portando l'automobile nelle case comuni.$$,
  $$Ford brought the moving assembly line to his Highland Park plant, cutting the build time of a Model T from twelve hours to ninety minutes and putting cars within reach of ordinary families.$$,
  1913, $$Modern$$, '20000000-0000-4000-8000-000000000028', '10000000-0000-4000-8000-000000000036', '{}'::uuid[]),
('30000000-0000-4000-8000-000000000037', $$economy_industry$$, $$agriculture$$, $$绿色革命$$, $$La Rivoluzione Verde$$, $$The Green Revolution$$,
  $$博洛格培育的矮秆高产小麦在墨西哥与印度等地大规模推广，把全球粮食产量翻番，避免了大范围饥荒。$$,
  $$Le varietà di grano nano ad alta resa selezionate da Borlaug, diffuse in Messico e in India, raddoppiarono la produzione alimentare mondiale ed evitarono carestie su vasta scala.$$,
  $$The dwarf high-yield wheat bred by Borlaug, rolled out in Mexico and India, doubled global food production and averted famines on a vast scale.$$,
  1960, $$Modern$$, '20000000-0000-4000-8000-000000000029', '10000000-0000-4000-8000-000000000037', '{}'::uuid[]);
